namespace sv_dc5de3381a504623b9b6506887022a89.Services;

/// <summary>
/// Scoped service (one per circuit) that holds the currently selected warehouse
/// and notifies all subscribed components when it changes.
/// </summary>
public class WarehouseStateService : IDisposable
{
    private string _currentWarehouseId = "WH-001";

    public string CurrentWarehouseId
    {
        get => _currentWarehouseId;
        set
        {
            if (_currentWarehouseId != value)
            {
                _currentWarehouseId = value;
                NotifyStateChanged();
            }
        }
    }

    public string CurrentWarehouseName =>
        Warehouses.FirstOrDefault(w => w.Id == _currentWarehouseId)?.Name ?? "Unknown";

    public static IReadOnlyList<Warehouse> Warehouses { get; } = new List<Warehouse>
    {
        new("WH-001", "Warehouse A — Downtown"),
        new("WH-002", "Warehouse B — Airport"),
        new("WH-003", "Warehouse C — Harbor"),
    };

    public event Action? OnChange;

    private void NotifyStateChanged() => OnChange?.Invoke();

    public void Dispose() => OnChange = null;
}

public record Warehouse(string Id, string Name);

namespace sv_dc5de3381a504623b9b6506887022a89.Services;

/// <summary>
/// Scoped service (one per circuit) that manages low-stock alert polling
/// and broadcasts updates to all subscribed components.
/// </summary>
public class InventoryAlertService : IDisposable
{
    private readonly WarehouseStateService _warehouseState;
    private readonly Random _random = new();
    private PeriodicTimer? _timer;
    private CancellationTokenSource? _cts;
    private int _subscriberCount;

    public int CurrentAlertCount { get; private set; }

    public event Action? OnAlertCountChanged;

    public InventoryAlertService(WarehouseStateService warehouseState)
    {
        _warehouseState = warehouseState;
    }

    /// <summary>
    /// Simulates a database query returning low-stock item count for a warehouse.
    /// </summary>
    public Task<int> GetLowStockCountAsync(string warehouseId)
    {
        // Simulate async DB call returning random 0-15
        return Task.FromResult(_random.Next(0, 16));
    }

    /// <summary>
    /// Starts polling if not already running. Multiple components can subscribe;
    /// polling stops only when all unsubscribe.
    /// </summary>
    public void StartPolling()
    {
        _subscriberCount++;
        if (_subscriberCount == 1)
        {
            _cts = new CancellationTokenSource();
            _timer = new PeriodicTimer(TimeSpan.FromSeconds(10));
            _ = PollLoopAsync(_cts.Token);
        }
    }

    /// <summary>
    /// Decrements subscriber count; stops polling when no subscribers remain.
    /// </summary>
    public void StopPolling()
    {
        _subscriberCount = Math.Max(0, _subscriberCount - 1);
        if (_subscriberCount == 0)
        {
            CancelPolling();
        }
    }

    /// <summary>
    /// Forces an immediate refresh (e.g., after warehouse change) and notifies subscribers.
    /// </summary>
    public async Task RefreshAsync()
    {
        CurrentAlertCount = await GetLowStockCountAsync(_warehouseState.CurrentWarehouseId);
        OnAlertCountChanged?.Invoke();
    }

    private async Task PollLoopAsync(CancellationToken ct)
    {
        // Immediately fetch once on start
        await RefreshAsync();

        try
        {
            while (await _timer!.WaitForNextTickAsync(ct))
            {
                CurrentAlertCount = await GetLowStockCountAsync(_warehouseState.CurrentWarehouseId);
                OnAlertCountChanged?.Invoke();
            }
        }
        catch (OperationCanceledException)
        {
            // Expected on disposal/stop
        }
    }

    private void CancelPolling()
    {
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = null;
        _timer?.Dispose();
        _timer = null;
    }

    public void Dispose()
    {
        CancelPolling();
        OnAlertCountChanged = null;
    }
}

