@rendermode InteractiveServer
@using sv_dc5de3381a504623b9b6506887022a89.Services
@inject WarehouseStateService WarehouseState
@inject InventoryAlertService AlertService
@implements IDisposable

<div class="warehouse-selector">
    <select class="form-select form-select-sm" value="@WarehouseState.CurrentWarehouseId"
            @onchange="OnWarehouseChanged">
        @foreach (var wh in WarehouseStateService.Warehouses)
        {
            <option value="@wh.Id">@wh.Name</option>
        }
    </select>
</div>

@code {
    protected override void OnInitialized()
    {
        WarehouseState.OnChange += StateHasChanged;
    }

    private async Task OnWarehouseChanged(ChangeEventArgs e)
    {
        WarehouseState.CurrentWarehouseId = e.Value?.ToString() ?? "WH-001";
        // Immediately refresh alerts for the new warehouse
        await AlertService.RefreshAsync();
    }

    public void Dispose()
    {
        WarehouseState.OnChange -= StateHasChanged;
    }
}

